<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>WastedToken Mint - Challenge Coins</title>
<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body { 
  font-family: 'Segoe UI', Tahoma, sans-serif;
  background: #0a0a0a;
  color: #e0e0e0;
  min-height: 100vh;
  padding: 2rem;
}
#hero {
  display: flex;
  justify-content: center;
  align-items: center;
  margin-bottom: 3rem;
}
#coin-hero {
  display: block;
  width: 240px;
  height: 240px;
  border-radius: 50%;
  background: radial-gradient(circle at 30% 30%, #444 0%, #222 100%);
  box-shadow: 0 0 30px rgba(255, 215, 0, 0.3);
}
#about {
  max-width: 800px;
  margin: 0 auto 3rem;
  padding: 2rem;
  background: rgba(255,255,255,0.05);
  border-radius: 15px;
  border: 1px solid rgba(255,215,0,0.2);
}
#about h2 {
  color: #ffd700;
  margin-bottom: 1rem;
  text-align: center;
}
#about p {
  line-height: 1.6;
  text-align: center;
}
#editions {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 2rem;
  max-width: 1000px;
  margin: 0 auto;
  padding: 0 1rem;
}
.edition {
  background: rgba(0,0,0,0.3);
  border-radius: 12px;
  padding: 1.5rem;
  text-align: center;
  border: 1px solid rgba(255,215,0,0.1);
  position: relative;
  overflow: hidden;
}
.edition-canvas {
  width: 120px;
  height: 120px;
  margin: 0 auto 1rem;
  border-radius: 50%;
  background: radial-gradient(circle, #444 0%, #222 100%);
}
.edition::before {
  content: '';
  position: absolute;
  top: 0; left: 0; right: 0; bottom: 0;
  border-radius: 12px;
  pointer-events: none;
  box-shadow: 0 0 20px rgba(255,215,0,0.2);
}
.buy {
  background: linear-gradient(135deg, #ffd700, #daa520);
  color: #0a0a0a;
  border: none;
  padding: 0.75rem 2rem;
  font-size: 1rem;
  font-weight: bold;
  border-radius: 30px;
  cursor: pointer;
  transition: all 0.3s ease;
  box-shadow: 0 4px 15px rgba(218,165,32,0.3);
}
.buy:hover:not(:disabled) {
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(218,165,32,0.4);
}
.buy:disabled {
  opacity: 0.4;
  cursor: not-allowed;
  transform: none;
}
.edition[data-state="sold-out"] .status {
  color: #ff4444;
  font-weight: bold;
  margin-bottom: 0.5rem;
}
.edition[data-state="coming-soon"] .status {
  color: #44aa44;
  font-weight: bold;
  margin-bottom: 0.5rem;
}
.edition[data-edition="bronze"] .edition-canvas { background: radial-gradient(circle at 30% 30%, #8b4513 0%, #5d2906 100%); }
.edition[data-edition="silver"] .edition-canvas { background: radial-gradient(circle at 30% 30%, #c0c0c0 0%, #888888 100%); }
.edition[data-edition="gold"] .edition-canvas { background: radial-gradient(circle at 30% 30%, #daa520 0%, #8b4513 100%); }
.edition[data-edition="black"] .edition-canvas { background: radial-gradient(circle at 30% 30%, #1a1a1a 0%, #000000 100%); }
</style>
</head>
<body>
<section id="hero">
  <canvas id="coin-hero" width="240" height="240"></canvas>
</section>

<section id="about">
  <h2>About WastedToken Mint</h2>
  <p>Founded in 2017, WastedToken Mint crafts elite challenge coins for the most discerning collectors and organizations. Each coin is meticulously minted using proprietary techniques that create a tactile experience of prestige. Our coins feature a reeded edge, metallic finish with dynamic highlights, and embossed emblems that tell a story of achievement and dedication.</p>
  <p>From corporate milestones to personal triumphs, our collectible coins serve as permanent symbols of accomplishment. Every piece is a testament to craftsmanship, combining traditional minting artistry with modern innovation.</p>
</section>

<section id="editions">
  <div class="edition" data-edition="bronze" data-state="available">
    <div class="status">BRONZE EDITION</div>
    <canvas class="edition-canvas"></canvas>
    <button class="buy">Add to cart</button>
  </div>

  <div class="edition" data-edition="silver" data-state="available">
    <div class="status">SILVER EDITION</div>
    <canvas class="edition-canvas"></canvas>
    <button class="buy">Add to cart</button>
  </div>

  <div class="edition" data-edition="gold" data-state="sold-out">
    <div class="status">SOLD OUT</div>
    <canvas class="edition-canvas"></canvas>
    <button class="buy" disabled>SOLD OUT</button>
  </div>

  <div class="edition" data-edition="black" data-state="coming-soon">
    <div class="status">MINTING FALL 2024</div>
    <canvas class="edition-canvas"></canvas>
    <button class="buy" disabled>MINTING NEXT SEASON</button>
  </div>
</section>

<script>
(function() {
  const canvas = document.getElementById('coin-hero');
  const ctx = canvas.getContext('2d');
  const W = canvas.width, H = canvas.height;
  const CX = W/2, CY = H/2;
  const R = 80;

  let t = 0;
  let rafId = null;

  function render(time) {
    t = time;
    draw();
  }

  function draw() {
    ctx.clearRect(0, 0, W, H);

    const theta = t * Math.PI * 2;
    const phi = t * Math.PI;

    ctx.save();
    ctx.translate(CX, CY);
    ctx.rotate(theta);
    ctx.scale(1, Math.cos(phi));

    // Draw reeded edge
    ctx.strokeStyle = '#555';
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.arc(0, 0, R, 0, Math.PI * 2);
    ctx.stroke();

    // Reeded texture
    for(let i = 0; i < 24; i++) {
      const a = i * Math.PI * 2 / 24;
      ctx.beginPath();
      ctx.moveTo(Math.cos(a) * (R-4), Math.sin(a) * (R-4));
      ctx.lineTo(Math.cos(a) * (R+4), Math.sin(a) * (R+4));
      ctx.strokeStyle = '#333';
      ctx.lineWidth = 1.5;
      ctx.stroke();
    }

    // Metallic gradient
    const grad = ctx.createRadialGradient(-R*0.3, -R*0.3, 1, 0, 0, R);
    grad.addColorStop(0, 'rgba(255,255,255,0.9)');
    grad.addColorStop(0.3, 'rgba(200,200,200,0.7)');
    grad.addColorStop(0.6, 'rgba(150,150,150,0.5)');
    grad.addColorStop(1, 'rgba(50,50,50,0.8)');

    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.arc(0, 0, R, 0, Math.PI * 2);
    ctx.fill();

    // Specular highlight
    const hl = Math.sin(theta * 2) * 0.5 + 0.5;
    ctx.fillStyle = `rgba(255,255,255,${0.8 + hl * 0.2})`;
    ctx.beginPath();
    ctx.moveTo(-R*0.8, -R*0.5);
    ctx.lineTo(R*0.3, -R*0.3);
    ctx.lineTo(R*0.1, R*0.4);
    ctx.closePath();
    ctx.fill();

    // Face content
    if(Math.abs(phi - Math.PI/2) < 0.1 || phi > 3*Math.PI/2) {
      // Back face
      ctx.fillStyle = '#fff';
      ctx.font = 'bold 14px Arial';
      ctx.textAlign = 'center';
      ctx.fillText('10,000', 0, -5);
      ctx.font = '10px Arial';
      ctx.fillText('TOKENS', 0, 10);
    } else {
      // Front face
      ctx.fillStyle = '#fff';
      ctx.beginPath();
      ctx.moveTo(-20, -15);
      ctx.lineTo(-10, -25);
      ctx.lineTo(0, -15);
      ctx.lineTo(10, -25);
      ctx.lineTo(20, -15);
      ctx.lineTo(15, 15);
      ctx.lineTo(-15, 15);
      ctx.closePath();
      ctx.fillStyle = '#ffd700';
      ctx.strokeStyle = '#daa520';
      ctx.lineWidth = 1.5;
      ctx.stroke();
      ctx.fill();

      ctx.fillStyle = '#0a0a0a';
      ctx.font = 'bold 10px Arial';
      ctx.textAlign = 'center';
      ctx.fillText('WT', 0, 5);
    }

    ctx.restore();
  }

  function start() {
    rafId = requestAnimationFrame(function loop(ts) {
      const progress = (ts / 10000) % 1;
      render(progress);
      rafId = requestAnimationFrame(loop);
    });
  }

  window.demo = {
    canvas: canvas,
    setTime: function(time) {
      render(time);
    },
    pause: function() {
      if(rafId) {
        cancelAnimationFrame(rafId);
        rafId = null;
      }
    }
  };

  // Initialize edition canvases
  document.querySelectorAll('.edition-canvas').forEach(c => {
    const ctx2 = c.getContext('2d');
    const W2 = c.width, H2 = c.height;
    const CX2 = W2/2, CY2 = H2/2;
    const R2 = 35;

    function drawEdition() {
      ctx2.clearRect(0, 0, W2, H2);

      const grad = ctx2.createRadialGradient(-R2*0.3, -R2*0.3, 1, 0, 0, R2);
      grad.addColorStop(0, 'rgba(255,255,255,0.9)');
      grad.addColorStop(0.3, 'rgba(200,200,200,0.7)');
      grad.addColorStop(0.6, 'rgba(150,150,150,0.5)');
      grad.addColorStop(1, 'rgba(50,50,50,0.8)');

      ctx2.fillStyle = grad;
      ctx2.beginPath();
      ctx2.arc(CX2, CY2, R2, 0, Math.PI * 2);
      ctx2.fill();

      // Reeded edge
      ctx2.strokeStyle = '#555';
      ctx2.lineWidth = 1;
      ctx2.beginPath();
      ctx2.arc(CX2, CY2, R2, 0, Math.PI * 2);
      ctx2.stroke();

      for(let i = 0; i < 12; i++) {
        const a = i * Math.PI * 2 / 12;
        ctx2.beginPath();
        ctx2.moveTo(CX2 + Math.cos(a) * (R2-3), CY2 + Math.sin(a) * (R2-3));
        ctx2.lineTo(CX2 + Math.cos(a) * (R2+3), CY2 + Math.sin(a) * (R2+3));
        ctx2.strokeStyle = '#333';
        ctx2.lineWidth = 1;
        ctx2.stroke();
      }

      // Face content
      const isBack = Math.random() > 0.5;
      if(isBack) {
        ctx2.fillStyle = '#fff';
        ctx2.font = 'bold 8px Arial';
        ctx2.textAlign = 'center';
        ctx2.fillText('10K', CX2, CY2 - 3);
        ctx2.fillText('TOKENS', CX2, CY2 + 5);
      } else {
        ctx2.fillStyle = '#fff';
        ctx2.beginPath();
        ctx2.moveTo(CX2-12, CY2-9);
        ctx2.lineTo(CX2-6, CY2-15);
        ctx2.lineTo(CX2, CY2-9);
        ctx2.lineTo(CX2+6, CY2-15);
        ctx2.lineTo(CX2+12, CY2-9);
        ctx2.lineTo(CX2+10, CY2+9);
        ctx2.lineTo(CX2-10, CY2+9);
        ctx2.closePath();
        ctx2.fillStyle = '#ffd700';
        ctx2.strokeStyle = '#daa520';
        ctx2.lineWidth = 1;
        ctx2.stroke();
        ctx2.fill();

        ctx2.fillStyle = '#0a0a0a';
        ctx2.font = 'bold 7px Arial';
        ctx2.textAlign = 'center';
        ctx2.fillText('WT', CX2, CY2 + 4);
      }
    }

    drawEdition();
  });

  start();
})();
</script>
</body>
</html>
